+			// Fall back to rig path (shouldn't happen in normal setup)
+			witnessDir = r.Path
+		}
+	}
+
 	// Ensure Claude settings exist (autonomous role needs mail in SessionStart)
-	if err := claude.EnsureSettingsForRole(r.Path, "witness"); err != nil {
