 		return false, fmt.Errorf("ensuring Claude settings: %w", err)
 	}

 	// Create new tmux session
-	if err := t.NewSession(sessionName, r.Path); err != nil {
+	if err := t.NewSession(sessionName, witnessDir); err != nil {
